    let reused = a
        .seen
        .get(&track)
        .map(|old| old == &b.outcome)
        .unwrap_or(false);
    b.reused = reused;
    a.seen.insert(track, b.outcome.clone());
    if b.outcome == "allow" && a.blocked.contains(&b.subject) && !b.via.is_empty() {
