use crate::model::CaseReport;
use serde::Serialize;
use std::fs;
use std::path::Path;

#[derive(Serialize)]
struct RowOut {
    label: String,
    principal: String,
    resource: String,
    action: String,
    verdict: String,
    epoch: u64,
    reused: bool,
    batch_id: String,
    delegated_from: String,
}

#[derive(Serialize)]
struct CaseOut {
    name: String,
    ok: bool,
    decisions: Vec<RowOut>,
    stale: Vec<String>,
}

#[derive(Serialize)]
struct RootOut {
    cases: Vec<CaseOut>,
}

pub fn write_report(path: &Path, cases: &[CaseReport]) -> Result<(), String> {
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent).map_err(|e| format!("mkdir {}: {e}", parent.display()))?;
    }
    let payload = RootOut {
        cases: cases
            .iter()
            .map(|case| CaseOut {
                name: case.name.clone(),
                ok: case.ok,
                stale: case.stale.clone(),
                decisions: case
                    .decisions
