pub fn cast_f(a: &mut State, mut b: Decision, _c: bool) -> (Decision, Option<String>) {
    let track = State::track_key(&b.subject, &b.object, &b.mode);
    let reused = a
        .seen
        .get(&track)
        .map(|old| old == &b.outcome)
        .unwrap_or(false);
